const e=JSON.parse('{"key":"v-74cedd30","path":"/%E4%B8%AA%E4%BA%BA/1.html","title":"2023/5/9日志","lang":"zh-CN","frontmatter":{"title":"2023/5/9日志","cover":"https://api.likepoems.com/img/nature","icon":"edit","date":"2023-05-09T00:00:00.000Z","category":["个人日志"],"tag":["日志","个人"],"description":"无所事事？ 不知道什么原因，又想弄博客了，在各个云服务器厂商看来看去，最后还是选择了静态的,所以毫不犹豫的选择了gitee了,我想通过博客可以记录一些事情吧,也让我在互联网上留下一些痕迹。 启程 大致博客分为三个内容,学习上,生活上,还有博客更新上的,主要以学习为主吧。 谈谈最近 最近一直在捣鼓各种各样的东西,最后还是捣鼓了一个博客,对了,近期还会做一个小项目,至少不会每天活在焦虑中了吧","head":[["meta",{"property":"og:url","content":"https://skym1.gitee.io/%E4%B8%AA%E4%BA%BA/1.html"}],["meta",{"property":"og:site_name","content":"Skyme的博客"}],["meta",{"property":"og:title","content":"2023/5/9日志"}],["meta",{"property":"og:description","content":"无所事事？ 不知道什么原因，又想弄博客了，在各个云服务器厂商看来看去，最后还是选择了静态的,所以毫不犹豫的选择了gitee了,我想通过博客可以记录一些事情吧,也让我在互联网上留下一些痕迹。 启程 大致博客分为三个内容,学习上,生活上,还有博客更新上的,主要以学习为主吧。 谈谈最近 最近一直在捣鼓各种各样的东西,最后还是捣鼓了一个博客,对了,近期还会做一个小项目,至少不会每天活在焦虑中了吧"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://api.likepoems.com/img/nature"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-08-28T01:15:29.000Z"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:image:alt","content":"2023/5/9日志"}],["meta",{"property":"article:author","content":"Skyme"}],["meta",{"property":"article:tag","content":"日志"}],["meta",{"property":"article:tag","content":"个人"}],["meta",{"property":"article:published_time","content":"2023-05-09T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-08-28T01:15:29.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"2023/5/9日志\\",\\"image\\":[\\"https://api.likepoems.com/img/nature\\"],\\"datePublished\\":\\"2023-05-09T00:00:00.000Z\\",\\"dateModified\\":\\"2023-08-28T01:15:29.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Skyme\\",\\"url\\":\\"https://skym1.gitee.io\\"}]}"]]},"headers":[{"level":3,"title":"无所事事？","slug":"无所事事","link":"#无所事事","children":[]},{"level":3,"title":"启程","slug":"启程","link":"#启程","children":[]},{"level":3,"title":"谈谈最近","slug":"谈谈最近","link":"#谈谈最近","children":[]}],"git":{"createdTime":1693185329000,"updatedTime":1693185329000,"contributors":[{"name":"Skym1","email":"412399240@qq.com","commits":1}]},"readingTime":{"minutes":0.72,"words":216},"filePathRelative":"个人/1.md","localizedDate":"2023年5月9日","excerpt":"<h3> 无所事事？</h3>\\n<p>不知道什么原因，又想弄博客了，在各个云服务器厂商看来看去，最后还是选择了静态的,所以毫不犹豫的选择了gitee了,我想通过博客可以记录一些事情吧,也让我在互联网上留下一些痕迹。</p>\\n<h3> 启程</h3>\\n<p>大致博客分为三个内容,学习上,生活上,还有博客更新上的,主要以学习为主吧。</p>\\n<h3> 谈谈最近</h3>\\n<p>最近一直在捣鼓各种各样的东西,最后还是捣鼓了一个博客,对了,近期还会做一个小项目,至少不会每天活在焦虑中了吧</p>\\n<figure><img src=\\"https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/blog/强子哥壁纸.png\\" alt=\\"\\" tabindex=\\"0\\" loading=\\"lazy\\"><figcaption></figcaption></figure>","autoDesc":true}');export{e as data};
